from project_config import dataset_paths
from dataset.AbstractDataset import AbstractDataset
import os
import numpy as np
from PIL import Image

class CocoGlide(AbstractDataset):
    """
    Structure:
    CocoGlide
    ├── images (e.g., 285.png)
    └── masks  (e.g., 285.png)
    """

    def __init__(self, crop_size, grid_crop, img_list: str, max_dim=None, aug=None):
        super().__init__(crop_size, grid_crop, max_dim, aug=aug)
        self._root_path = dataset_paths['CocoGlide']
        
        # Read the list file (generated by your script)
        from project_config import project_root
        list_path = project_root / img_list if not os.path.isabs(img_list) else img_list
        
        with open(list_path, "r") as f:
            lines = f.readlines()
        
        # list entries: images/filename.png,masks/filename.png
        self.img_list = [t.strip().split(',') for t in lines]


    def get_img(self, index):
        assert 0 <= index < len(self.img_list), f"Index {index} out of range!"
        
        rgb_path = os.path.join(self._root_path, self.img_list[index][0])
        mask_path = os.path.join(self._root_path, self.img_list[index][1])


        # Load and normalize mask (0 and 1)
        mask = np.array(Image.open(mask_path).convert("L"))
        mask[mask > 0] = 1

        assert os.path.isfile(rgb_path), f"Image not found: {rgb_path}"
        return self._create_tensor(mask=mask, rgb_path=rgb_path)

    def __len__(self):
        return len(self.img_list)